from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetPluginNode(BaseNode):
    name = "Prism: Get Plugin"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("plugin_name", "string", widget_type="text", default="USD")
        self.add_output("plugin", "any")
        self.add_output("is_loaded", "bool")
        self.add_output("plugin_path", "string")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        name = inputs.get('plugin_name') or ''
        if core is None:
            self.log_error("No PrismCore found. Add a prism_core_init node to your graph and connect its exec_out before this node.")
            return {'plugin': None, 'is_loaded': False, 'plugin_path': ''}
        try:
            plugin = None
            if hasattr(core, 'plugins') and hasattr(core.plugins, 'getPlugin'):
                plugin = core.plugins.getPlugin(name)
            elif hasattr(core, 'getPlugin'):
                plugin = core.getPlugin(name)
            loaded = plugin is not None
            ppath = ''
            if loaded:
                for attr in ('pluginPath', 'pluginDirectory', 'path'):
                    if hasattr(plugin, attr):
                        ppath = str(getattr(plugin, attr) or '')
                        if ppath: break
            self.log_info(f"Plugin '{name}' loaded={loaded} path={ppath}")
            return {'plugin': plugin, 'is_loaded': loaded, 'plugin_path': ppath}
        except Exception as e:
            self.log_error(f"getPlugin failed: {e}")
            return {'plugin': None, 'is_loaded': False, 'plugin_path': ''}

def register_node():
    return PrismGetPluginNode
